sql:
SELECT region_name
FROM sa2_regions
WHERE population_density > 3000;

SELECT sa2_maincode_2016, tot_population
FROM census_data
WHERE sa2_maincode_2016 = 1;

SELECT tot_population
FROM census_data
WHERE sa2_maincode_2016 = 0 AND category_id = 0 AND version = '1.0';

SELECT dataset_id, COUNT(*) AS metadata_entry_count
FROM metadata
WHERE dataset_id = 1;

SELECT tot_population, tot_gh 
FROM census_data 
WHERE sa2_maincode_2016 = 0 AND dataset_id = 0 AND version = '1.0';

SELECT tot_population
FROM census_data
WHERE sa2_maincode_2016 = 1 AND dataset_id = 0;

SELECT tot_population AS total_population
FROM census_data
WHERE sa2_maincode_2016 = 12345 AND dataset_id = 0 AND version = '1.0';

SELECT SUM(tot_population) AS total_population
FROM census_data
WHERE sa2_maincode_2016 = 0;
